from fastapi import FastAPI
from fastapi.responses import StreamingResponse
import anthropic

app = FastAPI()
client = anthropic.Anthropic()

@app.post("/chat/stream")
async def stream_chat(prompt: str):
    def generate():
        with client.messages.stream(
            model="claude-opus-4-8",
            max_tokens=1024,
            messages=[{"role": "user", "content": prompt}],
        ) as stream:
            for text in stream.text_stream:
                # SSE format: "data: <payload>\n\n"
                yield f"data: {text}\n\n"
        yield "data: [DONE]\n\n"

    return StreamingResponse(
        generate(),
        media_type="text/event-stream",
        headers={
            "Cache-Control": "no-cache",
            "X-Accel-Buffering": "no",  # Disable nginx buffering
        },
    )

const Anthropic = require('@anthropic-ai/sdk');
const express = require('express');

const app = express();
const client = new Anthropic();

app.post('/chat/stream', express.json(), async (req, res) => {
  res.setHeader('Content-Type', 'text/event-stream');
  res.setHeader('Cache-Control', 'no-cache');
  res.setHeader('Connection', 'keep-alive');

  const stream = await client.messages.stream({
    model: 'claude-opus-4-8',
    max_tokens: 1024,
    messages: [{ role: 'user', content: req.body.prompt }],
  });

  for await (const chunk of stream) {
    if (chunk.type === 'content_block_delta' && chunk.delta.type === 'text_delta') {
      res.write(`data: ${JSON.stringify({ text: chunk.delta.text })}\n\n`);
    }
  }
  res.write('data: [DONE]\n\n');
  res.end();
});

tools = [{
    "name": "get_weather",
    "description": "Get weather for a city",
    "input_schema": {
        "type": "object",
        "properties": {"city": {"type": "string"}},
        "required": ["city"],
    },
}]

with client.messages.stream(
    model="claude-opus-4-8",
    max_tokens=512,
    tools=tools,
    messages=[{"role": "user", "content": "What's the weather in Paris?"}],
) as stream:
    current_tool_input = ""
    for event in stream:
        if event.type == "content_block_start":
            if event.content_block.type == "tool_use":
                print(f"\nTool call: {event.content_block.name}")
                current_tool_input = ""
        elif event.type == "content_block_delta":
            if event.delta.type == "text_delta":
                print(event.delta.text, end="", flush=True)
            elif event.delta.type == "input_json_delta":
                current_tool_input += event.delta.partial_json
        elif event.type == "content_block_stop":
            if current_tool_input:
                import json
                print(f"Tool input: {json.loads(current_tool_input)}")

import anthropic
import time

def stream_with_retry(prompt: str, max_retries: int = 3) -> str:
    client = anthropic.Anthropic()
    delay = 1.0
    last_error = None

    for attempt in range(max_retries):
        collected = []
        try:
            with client.messages.stream(
                model="claude-opus-4-8",
                max_tokens=1024,
                messages=[{"role": "user", "content": prompt}],
            ) as stream:
                for text in stream.text_stream:
                    collected.append(text)
            return "".join(collected)

        except anthropic.APIConnectionError as e:
            # Network issue — safe to retry from scratch
            last_error = e
            if attempt < max_retries - 1:
                time.sleep(delay)
                delay *= 2
        except anthropic.RateLimitError as e:
            last_error = e
            retry_after = float(e.response.headers.get("retry-after", delay))
            time.sleep(retry_after)
        except anthropic.APIStatusError as e:
            if e.status_code in (500, 529):
                # Overloaded — retry
                last_error = e
                time.sleep(delay)
                delay *= 2
            else:
                raise  # 4xx errors are not retryable

    raise last_error

async function streamChat(prompt, onToken) {
  const response = await fetch('/chat/stream', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ prompt }),
  });

  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let buffer = '';

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;

    buffer += decoder.decode(value, { stream: true });
    const lines = buffer.split('\n');
    buffer = lines.pop(); // keep partial line

    for (const line of lines) {
      if (line.startsWith('data: ')) {
        const data = line.slice(6);
        if (data === '[DONE]') return;
        try {
          const parsed = JSON.parse(data);
          onToken(parsed.text);
        } catch {
          // plain text SSE — use data directly
          onToken(data);
        }
      }
    }
  }
}

